def solution(a_limit: int = 100, b_limit: int = 100) -> int:
    """
    Returns the maximum sum of digits for a^b where a < a_limit and b < b_limit.
    """
    max_sum = 0
    for a in range(1, a_limit):
        for b in range(1, b_limit):
            # Calculate power and convert to string to sum digits
            current_sum = sum(int(digit) for digit in str(a**b))
            if current_sum > max_sum:
                max_sum = current_sum
    return max_sum


if __name__ == "__main__":
    # Project Euler Problem 56
    print(f"Maximum digital sum: {solution(100, 100)}")

